import "math"

func solve(nums []int64) int64 {
	// Store indices of 1s and 2s
	indices1 := []int{}
	indices2 := []int{}

	for i, val := range nums {
		if val == 1 {
			indices1 = append(indices1, i)
		} else if val == 2 {
			indices2 = append(indices2, i)
		}
	}

	// If either 1s or 2s are missing, no effective pair exists
	if len(indices1) == 0 || len(indices2) == 0 {
		return -1
	}

	minDiff := math.MaxInt64

	// Iterate over all pairs (i, j) where nums[i] == 1 and nums[j] == 2
	for _, i := range indices1 {
		for _, j := range indices2 {
			diff := abs(i - j)
			if diff < minDiff {
				minDiff = diff
			}
		}
	}

	if minDiff == math.MaxInt64 {
		// This should not happen if the checks above are correct, but for safety
		return -1
	}

	return int64(minDiff)
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}
